class ChatListBox extends React.Component {

  componentWillReceiveProps(newProps) {
    if (!newProps.data.loading) {
      if (this.subscription) {
        return
      }
      this.subscription = newProps.data.subscribeToMore({
        document: SUBSCRIPTION_QUERY,
        updateQuery: (previousResult, {subscriptionData}) => {
          const newUser = subscriptionData.data.users.edges
          const newResult = {
            users: {
              edges: [
                ...previousResult.users.edges,
                ...newUser
              ]
            }
          }
          return newResult
        },
        onError: (err) => console.error(err)
      })
    }
  }

  render() {
    return <ListBox data={this.props.data} />
  }
}

const ChatListBoxWithData = graphql(LIST_BOX_QUERY)(ChatListBox)

export default ChatListBoxWithData

const networkInterface = createNetworkInterface({
  uri: 'http://localhost:5000/graphql'
})

const wsClient = new SubscriptionClient(`ws://localhost:5000/socket`, {
  reconnect: true
})

const networkInterfaceWithSubscriptions = addGraphQLSubscriptions(
  networkInterface,
  wsClient,
)

const client = new ApolloClient({
  dataIdFromObject: o => o.id,
  networkInterface: networkInterfaceWithSubscriptions
})

ReactDOM.render(
  <ApolloProvider client={client}>
    <ChatApp />
  </ApolloProvider>,
  document.getElementById('root')
)
```

In implementing support for ``prefetch_related`` on my project, it would have been handy to have a function to get the fields that are in the query to see where to add this optimization.  I created this function:

    def collect_fields(node):
        """Get all the unique field names that are eligible for optimization"""
        fields = set()
        for leaf in node:
            if leaf.get('kind', None) == "Field":
                fields.add(leaf["name"]["value"])
    
            if leaf.get("selection_set", None):
                fields = fields.union(collect_fields(leaf["selection_set"]["selections"]))
    
        return fields

Does it seem reasonable to add a function like this to the ``info`` object?  I'm happy to open a PR if so.

